import{_ as a,o as i,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Supreme Admin Guide","description":"","frontmatter":{},"headers":[],"relativePath":"roles/supreme-admin.md","filePath":"roles/supreme-admin.md"}'),s={name:"roles/supreme-admin.md"};function o(l,e,n,m,h,u){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="supreme-admin-guide" tabindex="-1">Supreme Admin Guide <a class="header-anchor" href="#supreme-admin-guide" aria-label="Permalink to &quot;Supreme Admin Guide&quot;">​</a></h1><p>This is the <strong>start here</strong> guide for <code>Supreme Admin</code> users. It is a map of the platform from the top level, plus a first-day checklist. It does <strong>not</strong> repeat every detailed how-to page. Use it as your reading path.</p><h2 id="what-only-a-supreme-admin-can-do" tabindex="-1">What only a Supreme Admin can do <a class="header-anchor" href="#what-only-a-supreme-admin-can-do" aria-label="Permalink to &quot;What only a Supreme Admin can do&quot;">​</a></h2><p>Some actions are not just &quot;high permission&quot; actions. They are hard-gated to Supreme Admin specifically, even if a custom role has powerful permissions.</p><p>These Supreme-Admin-only areas include:</p><ul><li>the platform-wide subscriptions and usage manager</li><li>plan creation and plan editing</li><li>direct plan assignment</li><li>suspension and unsuspension of kingdoms and alliances</li><li>the admin subscription requests queue</li><li>support links configuration</li><li>role and permission management</li></ul><p>If you need the full guardrail wording, see <a href="./protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="first-day-checklist" tabindex="-1">First-day checklist <a class="header-anchor" href="#first-day-checklist" aria-label="Permalink to &quot;First-day checklist&quot;">​</a></h2><p>If you are setting up the platform from scratch, follow this order:</p><ol><li>Read <a href="./overview.html">Roles Explained</a> and <a href="./../getting-started/navigating.html">Finding Your Way Around</a>.</li><li>Create your first <a href="./../how-to/manage-kingdoms.html">kingdom</a>.</li><li>Create the first <a href="./../how-to/create-user.html">users</a> and <a href="./../how-to/assign-roles.html">assign roles</a>.</li><li>Review or create your <a href="./../admin/manage-plans.html">plans</a>.</li><li>Configure <a href="./../admin/support-links.html">support links</a> so subscription requests have somewhere to point.</li><li>Enable and review <a href="./../admin/registration-settings.html">registration settings</a>.</li><li>Configure <a href="./../admin/email-settings.html">email settings</a> and send a test message.</li><li>Review the <a href="./../admin/subscriptions-dashboard.html">subscriptions dashboard</a>.</li></ol><h2 id="your-main-areas" tabindex="-1">Your main areas <a class="header-anchor" href="#your-main-areas" aria-label="Permalink to &quot;Your main areas&quot;">​</a></h2><p>As a Supreme Admin, these are the most important sections to learn:</p><ul><li><a href="./../admin/admin-overview.html">Platform Administration Overview</a></li><li><a href="./../how-to/manage-kingdoms.html">Create &amp; Manage Kingdoms</a></li><li><a href="./../how-to/create-user.html">Create a User</a></li><li><a href="./../how-to/assign-roles.html">Assign or Remove Roles</a></li><li><a href="./../admin/manage-plans.html">Create &amp; Edit Plans</a></li><li><a href="./../admin/subscription-requests.html">Handle Subscription Requests</a></li><li><a href="./../admin/support-links.html">Configure Support Links</a></li><li><a href="./../admin/email-settings.html">Email Settings</a></li><li><a href="./../admin/theme-settings.html">Theme Settings</a></li><li><a href="./../admin/registration-settings.html">Registration Settings</a></li></ul><h2 id="what-you-should-learn-after-that" tabindex="-1">What you should learn after that <a class="header-anchor" href="#what-you-should-learn-after-that" aria-label="Permalink to &quot;What you should learn after that&quot;">​</a></h2><ul><li><a href="./../subscriptions/overview.html">Subscriptions &amp; Quotas Explained</a></li><li><a href="./../reference/audit-logs.html">Read the Audit Logs</a></li><li><a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a></li><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li><li><a href="./../how-to/recycle-bin.html">Use the Recycle Bin</a></li></ul><h2 id="common-limits-even-for-you" tabindex="-1">Common limits even for you <a class="header-anchor" href="#common-limits-even-for-you" aria-label="Permalink to &quot;Common limits even for you&quot;">​</a></h2><p>Supreme Admin is the strongest role, but a few safety rules still apply:</p><ul><li>you cannot delete your own account</li><li>you cannot remove the last active Supreme Admin</li><li>some destructive actions are soft-delete first, not immediate purge</li></ul><p>Those rules are explained in <a href="./protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p>',19)])])}const c=a(s,[["render",o]]);export{p as __pageData,c as default};
